package com.digitaldentic.sistemaodontologico.security;

 import org.springframework.security.core.userdetails.User; import org.springframework.security.core.userdetails.UserDetails; import org.springframework.security.core.userdetails.UserDetailsService; import org.springframework.security.core.userdetails.UsernameNotFoundException; import org.springframework.stereotype.Service; import com.digitaldentic.sistemaodontologico.Entity.UsuarioEntity; import com.digitaldentic.sistemaodontologico.Repository.UsuarioRepository; @Service
public class UsuarioDetailsService implements UserDetailsService { private final UsuarioRepository usuarioRepository; public UsuarioDetailsService(UsuarioRepository usuarioRepository) { this.usuarioRepository = usuarioRepository; } @Override public UserDetails loadUserByUsername(String email) throws UsernameNotFoundException { UsuarioEntity usuario = usuarioRepository.findByEmail(email) .orElseThrow(() -> new UsernameNotFoundException("Usuario no encontrado")); return User.builder() .username(usuario.getEmail()) .password(usuario.getPassword()) .roles(usuario.getRol().name()) .disabled(!usuario.isActivo()) .build(); } }